import com.smartquiz.config.DBConnection; import java.sql.*; public class ActivateQuizzes { public static void main(String[] args) throws Exception { try (Connection conn = DBConnection.getConnection(); Statement stmt = conn.createStatement()) { stmt.executeUpdate("UPDATE quizzes SET start_time = DATE_SUB(NOW(), INTERVAL 1 HOUR), end_time = DATE_ADD(NOW(), INTERVAL 24 HOUR) WHERE title = \"Java Basics\""); System.out.println("Java Basics quiz activated."); } } }
